-- WinVote seed (idempotent) — schema winvote

begin;

insert into winvote.municipalities (name, created_by)
select 'เทศบาลนครนครราชสีมา','seed'
where not exists (select 1 from winvote.municipalities);

insert into winvote.districts (municipality_id, code, name, resident_target, created_by)
select mu.id, g.code, 'เขต '||g.code, 10000, 'seed'
from winvote.municipalities mu
cross join (values (1),(2),(3),(4)) g(code)
on conflict (municipality_id, code) do nothing;

